import { api } from './client'

export type WaitlistStatus = 'waiting' | 'invited' | 'enrolled' | 'declined'

export interface WaitlistEntryDto {
  id: string
  classroomId: string
  parentName: string
  parentPhone: string
  parentEmail: string | null
  childName: string | null
  childAge: number | null
  position: number
  leadId: string | null
  notes: string | null
  status: WaitlistStatus
  createdAt: string
}

export interface CreateWaitlistPayload {
  classroomId: string
  parentName: string
  parentPhone: string
  parentEmail?: string
  childName?: string
  childAge?: number
  leadId?: string
  notes?: string
}

export function fetchWaitlistByClassroom(classroomId: string): Promise<WaitlistEntryDto[]> {
  return api.get<WaitlistEntryDto[]>(`/waitlist/classroom/${classroomId}`)
}

export function addWaitlistEntry(payload: CreateWaitlistPayload): Promise<WaitlistEntryDto> {
  return api.post<WaitlistEntryDto>('/waitlist', payload)
}

export function inviteWaitlistEntry(id: string): Promise<WaitlistEntryDto> {
  return api.patch<WaitlistEntryDto>(`/waitlist/${id}/invite`)
}

export function markWaitlistEnrolled(id: string): Promise<WaitlistEntryDto> {
  return api.patch<WaitlistEntryDto>(`/waitlist/${id}/mark-enrolled`)
}

export function markWaitlistDeclined(id: string): Promise<WaitlistEntryDto> {
  return api.patch<WaitlistEntryDto>(`/waitlist/${id}/mark-declined`)
}

export function deleteWaitlistEntry(id: string): Promise<void> {
  return api.delete<void>(`/waitlist/${id}`)
}

export const WAITLIST_STATUS_LABELS: Record<WaitlistStatus, string> = {
  waiting: 'Ожидает',
  invited: 'Приглашён',
  enrolled: 'Зачислен',
  declined: 'Отказался',
}
