/**
 * AdminWaitlist — лист ожидания по группам.
 * Селектор группы → таблица записей + форма добавления + действия (приглас/зачислить/отказ/удалить).
 */

import { useEffect, useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { fetchClassrooms, type ClassroomDto } from '../api/classrooms'
import {
  fetchWaitlistByClassroom,
  addWaitlistEntry,
  inviteWaitlistEntry,
  markWaitlistEnrolled,
  markWaitlistDeclined,
  deleteWaitlistEntry,
  WAITLIST_STATUS_LABELS,
  type WaitlistEntryDto,
  type WaitlistStatus,
} from '../api/waitlist'

const STATUS_COLOR: Record<WaitlistStatus, string> = {
  waiting: '#FFD43C',
  invited: '#A9D8FF',
  enrolled: '#9FE8C7',
  declined: '#FFB4C8',
}

export default function AdminWaitlist() {
  const { toast, show } = useToast()

  const [classrooms, setClassrooms] = useState<ClassroomDto[]>([])
  const [classroomId, setClassroomId] = useState<string>('')
  const [entries, setEntries] = useState<WaitlistEntryDto[]>([])
  const [loading, setLoading] = useState(false)
  const [busyId, setBusyId] = useState<string | null>(null)

  // Add-entry form
  const [parentName, setParentName] = useState('')
  const [parentPhone, setParentPhone] = useState('')
  const [parentEmail, setParentEmail] = useState('')
  const [childName, setChildName] = useState('')
  const [childAge, setChildAge] = useState<number | ''>('')
  const [notes, setNotes] = useState('')
  const [adding, setAdding] = useState(false)

  useEffect(() => {
    fetchClassrooms()
      .then((rows) => {
        setClassrooms(rows)
        if (rows[0]) setClassroomId(rows[0].id)
      })
      .catch(() => show('Ошибка загрузки групп', 'error'))
  }, [])

  function loadEntries() {
    if (!classroomId) return
    setLoading(true)
    fetchWaitlistByClassroom(classroomId)
      .then(setEntries)
      .catch(() => show('Ошибка загрузки очереди', 'error'))
      .finally(() => setLoading(false))
  }

  useEffect(loadEntries, [classroomId])

  const activeClassroom = classrooms.find((c) => c.id === classroomId) ?? null

  async function handleAdd() {
    if (!classroomId) return
    if (!parentName.trim() || !parentPhone.trim()) {
      show('Заполните имя и телефон родителя', 'error')
      return
    }
    setAdding(true)
    try {
      const payload: Parameters<typeof addWaitlistEntry>[0] = {
        classroomId,
        parentName: parentName.trim(),
        parentPhone: parentPhone.trim(),
      }
      if (parentEmail.trim()) payload.parentEmail = parentEmail.trim()
      if (childName.trim()) payload.childName = childName.trim()
      if (typeof childAge === 'number') payload.childAge = childAge
      if (notes.trim()) payload.notes = notes.trim()
      await addWaitlistEntry(payload)
      show('Запись добавлена', 'success')
      setParentName(''); setParentPhone(''); setParentEmail('')
      setChildName(''); setChildAge(''); setNotes('')
      loadEntries()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setAdding(false)
    }
  }

  async function withBusy(id: string, fn: () => Promise<unknown>, msg: string) {
    setBusyId(id)
    try {
      await fn()
      show(msg, 'success')
      loadEntries()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setBusyId(null)
    }
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>📝</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Группы</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Лист ожидания</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1200, margin: '0 auto', padding: '20px 16px' }}>
        {/* Classroom selector */}
        <div className="kb-card" style={{ padding: 14, marginBottom: 16, display: 'flex', flexWrap: 'wrap', gap: 12, alignItems: 'center' }}>
          <label style={{ display: 'flex', flexDirection: 'column', gap: 4, fontSize: 12, flex: 1, minWidth: 240 }}>
            Группа
            <select value={classroomId} onChange={(e) => setClassroomId(e.target.value)} style={{ padding: 8, borderRadius: 8 }}>
              {classrooms.length === 0 && <option value="">— нет групп —</option>}
              {classrooms.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.name} ({c.studentCount}/{c.maxStudents})
                </option>
              ))}
            </select>
          </label>
          {activeClassroom && (
            <div style={{ fontSize: 12, color: 'var(--ink-soft)' }}>
              Заполнено: <b>{activeClassroom.studentCount}</b> из <b>{activeClassroom.maxStudents}</b>
            </div>
          )}
        </div>

        {/* Add form */}
        {classroomId && (
          <div className="kb-card" style={{ padding: 14, marginBottom: 16 }}>
            <h3 style={{ margin: '0 0 10px', fontSize: 16, fontWeight: 800 }}>Добавить запись</h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 8 }}>
              <input placeholder="Имя родителя*" value={parentName} onChange={(e) => setParentName(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
              <input placeholder="Телефон*" value={parentPhone} onChange={(e) => setParentPhone(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
              <input placeholder="Email" value={parentEmail} onChange={(e) => setParentEmail(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
              <input placeholder="Имя ребёнка" value={childName} onChange={(e) => setChildName(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
              <input type="number" placeholder="Возраст" value={childAge} onChange={(e) => setChildAge(e.target.value === '' ? '' : Number(e.target.value))} style={{ padding: 8, borderRadius: 8 }} />
              <input placeholder="Заметки" value={notes} onChange={(e) => setNotes(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
            </div>
            <div style={{ marginTop: 10 }}>
              <button className="kb-btn" disabled={adding} onClick={() => void handleAdd()} style={{ background: 'var(--violet)', color: '#fff' }}>
                {adding ? '…' : 'Добавить в очередь'}
              </button>
            </div>
          </div>
        )}

        {/* Table */}
        {loading ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
        ) : !classroomId ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Выберите группу</div>
        ) : entries.length === 0 ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Очередь пуста.</div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13, minWidth: 800 }}>
              <thead>
                <tr style={{ background: 'var(--paper-2, #f9f8ff)' }}>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>#</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Родитель</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Контакты</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Ребёнок</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Статус</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Действия</th>
                </tr>
              </thead>
              <tbody>
                {entries.map((e) => (
                  <tr key={e.id} style={{ borderTop: '1px solid var(--paper-3, #e5e2f0)' }}>
                    <td style={{ padding: 10, fontWeight: 700 }}>{e.position}</td>
                    <td style={{ padding: 10 }}>{e.parentName}</td>
                    <td style={{ padding: 10, fontSize: 12 }}>
                      <div>{e.parentPhone}</div>
                      {e.parentEmail && <div style={{ color: 'var(--ink-soft)' }}>{e.parentEmail}</div>}
                    </td>
                    <td style={{ padding: 10, fontSize: 12 }}>
                      {e.childName || '—'}{e.childAge != null ? `, ${e.childAge} лет` : ''}
                    </td>
                    <td style={{ padding: 10 }}>
                      <span style={{ background: STATUS_COLOR[e.status], padding: '3px 8px', borderRadius: 6, fontSize: 12, fontWeight: 700 }}>
                        {WAITLIST_STATUS_LABELS[e.status]}
                      </span>
                    </td>
                    <td style={{ padding: 10, display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                      {e.status === 'waiting' && (
                        <button className="kb-btn" disabled={busyId === e.id} onClick={() => void withBusy(e.id, () => inviteWaitlistEntry(e.id), 'Приглашение отправлено')} style={{ background: '#6b5ce7', color: '#fff', fontSize: 12, padding: '6px 10px' }}>
                          Пригласить
                        </button>
                      )}
                      {(e.status === 'waiting' || e.status === 'invited') && (
                        <button className="kb-btn" disabled={busyId === e.id} onClick={() => void withBusy(e.id, () => markWaitlistEnrolled(e.id), 'Отмечен как зачисленный')} style={{ background: '#059669', color: '#fff', fontSize: 12, padding: '6px 10px' }}>
                          Зачислен
                        </button>
                      )}
                      {e.status !== 'declined' && (
                        <button className="kb-btn" disabled={busyId === e.id} onClick={() => void withBusy(e.id, () => markWaitlistDeclined(e.id), 'Отказ зафиксирован')} style={{ background: '#b78103', color: '#fff', fontSize: 12, padding: '6px 10px' }}>
                          Отказался
                        </button>
                      )}
                      <button className="kb-btn" disabled={busyId === e.id} onClick={() => void withBusy(e.id, () => deleteWaitlistEntry(e.id), 'Удалено')} style={{ background: '#dc2626', color: '#fff', fontSize: 12, padding: '6px 10px' }}>
                        Удалить
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </PlatformShell>
  )
}
